def unify(expr1, expr2):
 if isinstance(expr1, str) and isinstance(expr2, str):
 if expr1 == expr2:
 return {}
 else:
 return None
 elif isinstance(expr1, tuple) and isinstance(expr2, tuple):
 if len(expr1) != len(expr2):
 return None
 substitution = {}
 for i in range(len(expr1)):
 sub = unify(expr1[i], expr2[i])
 if sub is None:
 return None
 substitution.update(sub)
 return substitution
 elif isinstance(expr1, str):
 return {expr1: expr2}
 elif isinstance(expr2, str):
 return {expr2: expr1}
 else:
 return None

